// ── VALIDATE (from shared/validate.js) ────────────────────────
const REQUIRED = ['title','url','source_slug'];
const MAX_LEN  = { title:500, url:2000, content_raw:50000, author:200 };

function validateItem(item) {
  const errors = [];
  for (const f of REQUIRED) {
    if (!item[f] || String(item[f]).trim() === '') errors.push({ field: f, error: 'required' });
  }
  if (item.url) { try { new URL(item.url); } catch { errors.push({ field:'url', error:'invalid URL' }); } }
  for (const [f, max] of Object.entries(MAX_LEN)) {
    if (item[f] && String(item[f]).length > max) errors.push({ field: f, error: `exceeds max ${max}` });
  }
  if (!Array.isArray(item.tags)) errors.push({ field:'tags', error:'must be array' });
  if (item.published_at) {
    const d = new Date(item.published_at);
    if (isNaN(d)) errors.push({ field:'published_at', error:'invalid date' });
    else if (d > new Date()) errors.push({ field:'published_at', error:'future date' });
  }
  return { valid: errors.length === 0, errors };
}

const valid = [], invalid = [];
for (const item of $input.all()) {
  const r = validateItem(item.json);
  if (r.valid) valid.push({ json: item.json });
  else {
    invalid.push({ json: item.json });
    console.log('[VALIDATE] rejected:', item.json.url, r.errors);
  }
}
console.log(`[VALIDATE] valid=${valid.length} invalid=${invalid.length}`);
return valid; // only valid items continue
